// ── Auto-download & cache image locally ──────────────────────────────────────
const downloadImage = async (url, folder, filename) => {
  const ext = url.split("?")[0].split(".").pop().replace(/[^a-z]/gi, "") || "jpg";
  const filePath = path.join(folder, `${filename}.${ext}`);
  if (fs.existsSync(filePath)) return; // already cached
  try {
    const res = await fetch(url);
    if (!res.ok) return;
    const buffer = Buffer.from(await res.arrayBuffer());
    fs.mkdirSync(folder, { recursive: true });
    fs.writeFileSync(filePath, buffer);
    console.log(`    💾 Saved ${filename}.${ext}`);
  } catch (e) {
    console.warn(`    ⚠ Could not download image for ${filename}`);
  }
};

