// ── Seed ──────────────────────────────────────────────────────────────────────
const seed = async () => {
  try {
    await connectDB();
    console.log("Connected to DB");

    await Promise.all([
      User.deleteMany({}),
      Product.deleteMany({}),
      Fighter.deleteMany({}),
      Coupon.deleteMany({}),
    ]);
    console.log("Cleared all collections");

    // Download & cache all images locally
    console.log("\nDownloading & caching fighter images...");
    for (const f of fighterDefs) {
      if (!f.imageUrl.startsWith("PASTE_")) {
        const slug = f.name.toLowerCase().replace(/\s+/g, "-");
        await downloadImage(f.imageUrl, IMG_DIR_FIGHTERS, slug);
      }
    }

    console.log("Downloading & caching product images...");
    for (const p of productDefs) {
      if (!p.imageUrl.startsWith("PASTE_")) {
        const slug = p.name.toLowerCase().replace(/\s+/g, "-").replace(/[^a-z0-9-]/g, "");
        await downloadImage(p.imageUrl, IMG_DIR_PRODUCTS, slug);
      }
    }

    const [adminPassword, userPassword] = await Promise.all([
      bcrypt.hash("admin123", 10),
      bcrypt.hash("user123", 10),
    ]);

    const fighters = fighterDefs;
    const products = productDefs.map((p, idx) => ({
      ...p,
      description: `${p.name} built for performance, durability, and daily training comfort.`,
      stock: 20 + (idx % 35),
      soldCount: 10 + idx * 3,
    }));

    await Promise.all([
      User.insertMany([
        { name: "Admin",    email: "admin@ufcstore.com", passwordHash: adminPassword, role: "admin" },
        { name: "Customer", email: "user@ufcstore.com",  passwordHash: userPassword,  role: "user"  },
      ]),
      Product.insertMany(products),
      Fighter.insertMany(fighters),
      Coupon.insertMany([{
        code: "UFC20",
        discountPercent: 20,
        minOrderValue: 100,
        expiresAt: new Date(Date.now() + 1000 * 60 * 60 * 24 * 60),
      }]),
    ]);

    console.log(`\n✅ Seed complete — ${products.length} products | ${fighters.length} fighters | 2 users | 1 coupon`);
    process.exit(0);
  } catch (err) {
    console.error("Seed failed:", err);
    process.exit(1);
  }
};

seed();